class CertificatePinningManager: NSObject {
    static let shared = CertificatePinningManager()

    private var pinnedCertificates: [String: Data] = [:]

    func configure() {
        loadPinnedCertificates()
    }

    private func loadPinnedCertificates() {
        // Load certificates from bundle
        guard let certPath = Bundle.main.path(forResource: "supabase-cert", ofType: "cer"),
              let certData = NSData(contentsOfFile: certPath) else {
            fatalError("Could not load pinned certificate")
        }
        pinnedCertificates["supabase.co"] = certData as Data
    }
}

