protocol PortfolioRepositoryProtocol {
    func fetchPortfolio(for investorId: UUID) async throws -> Portfolio
    func cachePortfolio(_ portfolio: Portfolio) async throws
    func getCachedPortfolio(for investorId: UUID) async throws -> Portfolio?
}

class PortfolioRepository: PortfolioRepositoryProtocol {
    private let supabaseClient: SupabaseClient
    private let coreDataStack: CoreDataStack
    private let offlineManager: OfflineManagerProtocol

    func fetchPortfolio(for investorId: UUID) async throws -> Portfolio {
        // Try cache first, then network
        if let cached = try await getCachedPortfolio(for: investorId) {
            return cached
        }

        let portfolio = try await fetchFromNetwork(investorId: investorId)
        try await cachePortfolio(portfolio)
        return portfolio
    }
}

@MainActor
class DashboardViewModel: ObservableObject {
    @Published var portfolio: Portfolio?
    @Published var recentTransactions: [Transaction] = []
    @Published var performanceData: [PerformanceData] = []
    @Published var isLoading = false
    @Published var errorMessage: String?

    private let portfolioService: PortfolioServiceProtocol
    private let transactionService: TransactionServiceProtocol

    init(portfolioService: PortfolioServiceProtocol, transactionService: TransactionServiceProtocol) {
        self.portfolioService = portfolioService
        self.transactionService = transactionService
    }

    func loadData() async {
        isLoading = true
        defer { isLoading = false }

        do {
            async let portfolioTask = loadPortfolio()
            async let transactionsTask = loadRecentTransactions()

            _ = try await (portfolioTask, transactionsTask)
        } catch {
            errorMessage = error.localizedDescription
        }
    }
}

